"""
MKT Original Layer — Jeremiah chapters 22–24
Run: python3 scripts/zc-original-jeremiah-22-24-fill.py

Key lexical decisions:
- da'at YHWH (22:16): 'knowing YHWH' = practicing justice; the prophets' central
  definition of covenant knowledge, not intellectual assent.
- Coniah as signet ring (22:24): the royal seal removed; the Jehoiachin curse and its
  NT genealogical resolution through the virgin birth (Matt 1:12 + Luke 3:27).
- tzemach tzaddiq (23:5-6): 'righteous Branch' — the messianic title used again in
  Jer 33:15, Zech 3:8, 6:12; YHWH Tsidqenu (LORD Our Righteousness) is the
  messianic name that reverses Israel's inability to be righteous.
- sod YHWH (23:18): 'the council of the LORD' — the criterion for authentic prophecy;
  only those who have stood in YHWH's divine council have the genuine word.
- massa (23:33-36): 'burden/oracle' — the pun Jeremiah exploits: prophets who
  habitually call everything an 'oracle' have made themselves the burden.
- lev lad'at (24:7): 'heart to know me' — the new-covenant promise in miniature,
  anticipating 31:33-34 by granting to the exiles what the nation refused.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JER_ORIGINAL = {
  "22": {
    "1": "<p>The messenger formula opens a throne-room oracle: Jeremiah is sent to the palace (<em>beit hamelech</em>) itself — the seat of Davidic authority — to confront the reigning king directly. This is the most confrontational prophetic assignment in Jeremiah&apos;s ministry up to this point; the setting at the palace gates (v. 2) ensures maximum public exposure.</p>",
    "2": "<p><strong>hayoshev al-kise David</strong> (<em>hayyōšēb ʿal-kissēʾ dāwid</em>): &apos;You who sit on the throne of David.&apos; The address establishes Davidic covenant accountability: sitting on David&apos;s throne is not merely political office but covenant succession. The king who occupies that throne inherits not only David&apos;s authority but David&apos;s covenantal responsibilities — the obligations of the shepherd-king (cf. Ezek 34:2-4 where YHWH castigates the same shepherds). Entry through these gates (<em>sha&apos;ar hazeh</em>) marks the subjects as those under the king&apos;s jurisdiction and therefore his responsibility.</p>",
    "3": "<p><strong>asu mishpat utzedaqah</strong> (<em>ʿăśû mišpāṭ ûṣĕdāqāh</em>): &apos;Do what is just and right.&apos; The <em>mishpat-tzedaqah</em> pair is the prophetic shorthand for covenant righteousness — appearing together in Isa 1:27; 9:7; Amos 5:24; Mic 6:8. <em>Mishpat</em> (justice, the execution of legally right outcomes) and <em>tzedaqah</em> (righteousness, the relational quality of right-standing) together describe both procedural and character-based right living. The three protected categories — <em>ger</em> (foreigner), <em>yatom</em> (orphan), <em>almanah</em> (widow) — are the covenant&apos;s permanently vulnerable members, whose protection is a test case for whether covenant justice is real (Exod 22:21-24; Deut 10:18; Ps 146:9).</p>",
    "4": "<p><strong>ki im asoh ta&apos;asu et-hadavar hazeh uvau visha&apos;arei habayit hazeh melakim yoshavim ledavid al-kis&apos;o</strong>: &apos;For if you carefully obey this command, then kings will continue to pass through the gates of this palace.&apos; The double infinitive absolute (<em>asoh ta&apos;asu</em>, &apos;doing you shall do&apos;) intensifies the conditionality: if and only if justice is genuinely practiced, the Davidic dynasty continues. The royal continuity is placed entirely on the condition of covenantal obedience — not on military power or political skill. Chariots and horses (<em>rakhuv berekev uvesusim</em>) denote the full ceremonial display of royal power, promised as the reward of obedience.</p>",
    "5": "<p><strong>ki im lo tishme&apos;u et-hadvarim ha&apos;elleh bishvi nishba&apos;ti</strong> (<em>kî ʾim-lōʾ tišmĕʿû ʾet-haddĕbārîm hāʾēlleh bî nišbaʿtî</em>): &apos;But if you refuse to listen to these words, I swear by myself, declares the LORD.&apos; <em>Bishvi nishba&apos;ti</em> (I swear by myself) — the divine self-oath, used when no higher authority exists to swear by (cf. Gen 22:16; Isa 45:23; Heb 6:13). YHWH&apos;s self-oath is the strongest possible guarantee: the palace will become a ruin (<em>chorba</em>). The same oath form is used for the Abrahamic promises (Gen 22:16) and for eschatological judgment (Isa 45:23) — placing this royal warning in the same register as the founding covenantal promises.</p>",
    "6": "<p><strong>ki-koh amar YHWH al-beit melech Yehudah gilad attah li rosh halvanon</strong> (<em>kî-kōh ʾāmar Yhwh ʿal-bêt melek yĕhûdāh gilʿād ʾattāh lî rōʾš hallĕbānôn</em>): &apos;You are Gilead to me, the heights of Lebanon — yet I will surely make you a wasteland.&apos; Gilead and Lebanon were proverbial for lushness, abundant timber, and fertility (cf. 22:23; Mic 7:14; Nah 1:4). The palace built of Lebanese cedar (cf. 1 Kings 7:2-3: &apos;the palace of the forest of Lebanon&apos;) is itself the cedar-landmark. The irony is embedded in the beauty: the very thing that makes the palace magnificent (its cedar construction) is what fuels its destruction in v. 7 — the finest cedar trees felled and thrown into the fire.</p>",
    "7": "<p><strong>vehiqaddashti aleikha mashchitim ish uklav</strong> (<em>wĕhiqqaddaštî ʿālêkā maśḥîtîm ʾîš ûkĕlāyw</em>): &apos;I will send destroyers against you, each armed with weapons; they will fell your finest cedar trees and throw them into the fire.&apos; <em>Mashchitim</em> (destroyers) — the same root as the corrupt earth before the flood (Gen 6:12) and the destroying angel at the Exodus (Exod 12:23). YHWH &apos;consecrates&apos; (<em>hiqdash</em>) these destroyers — using holy-war vocabulary for the enemies. The cedar trees (&apos;your finest&apos;, <em>arzel arzicha</em>) being cut and burned inverts the palace&apos;s construction: built from Lebanon&apos;s cedars (1 Kgs 7), it returns to ash.</p>",
    "8": "<p><strong>ve&apos;avru goyim rabbim al-ha&apos;ir hazot ve&apos;amru ish el-re&apos;ehu</strong>: &apos;Many nations will pass by this city, and they will ask one another, &apos;Why has the LORD done this to such a great city?&apos;&apos; The tourist-horror response from passing nations echoes the covenant curse of Deut 29:24-26 almost verbatim: &apos;all the nations will ask, &apos;Why has the LORD done this to this land?&apos;&apos; The question from outsiders (<em>goyim rabbim</em>) is rhetorical — they are not expecting an answer but drawing attention to the theological magnitude of what has happened to a city YHWH specially chose.</p>",
    "9": "<p><strong>tachat asher azavu et-brit YHWH eloheihem</strong> (<em>taḥat ʾăšer ʿāzĕbû ʾet-bĕrît Yhwh ʾĕlōhêhem</em>): &apos;Because they abandoned the covenant of the LORD their God.&apos; The answer to v. 8&apos;s question is delivered in one clause: covenant abandonment. The word <em>azav</em> (abandoned/forsook) is the strongest verb for willful covenant breach — used for Hagar abandoning Ishmael (Gen 21:14), for children abandoning a parent, and for Israel abandoning YHWH (1 Kgs 18:18; Jer 1:16; 2:13). Serving other gods (<em>vayishttachavu la&apos;elohim acherim</em>) is the specific content of the abandonment.</p>",
    "10": "<p><strong>al-tivku lamet veal-tanudu lo</strong> (<em>ʾal-tibkû lāmēt wĕʾal-tānūdû lô</em>): &apos;Do not weep for the dead king or mourn for him; but weep bitterly for the one who goes into exile.&apos; The &apos;dead king&apos; is Josiah, killed at Megiddo (609 BCE) — the greatest reforming king of Judah&apos;s last century. The &apos;one who goes into exile&apos; is Jehoahaz (Shallum), deposed by Pharaoh Neco after three months and taken to Egypt (2 Kgs 23:31-34). The counter-intuitive reversal: Josiah who died at home is less to be mourned than Jehoahaz who lives in exile; death is less final than exile from the covenant land. This reflects the Deuteronomic theology that life in the covenant land with YHWH is the supreme good.</p>",
    "11": "<p><strong>ki-koh amar YHWH el-Shallum ben-Yoshiyahu</strong>: &apos;For this is what the LORD says about Shallum son of Josiah.&apos; The throne name &apos;Jehoahaz&apos; is replaced with the personal name &apos;Shallum&apos; (<em>shallum</em>, related to <em>shalom</em>, peace/wholeness) — an ironic use since he will die far from peace. Historical note: Jehoahaz/Shallum reigned only three months before Pharaoh Neco deposed him and installed Jehoiakim in his place, making him the first Davidic king taken captive to a foreign land in Jeremiah&apos;s lifetime.</p>",
    "12": "<p><strong>ki bimakom asher heggelu oto sham yamut veet-ha&apos;aretz hazot lo-yireh od</strong>: &apos;He will die in the place he has been taken captive, and he will never see this land again.&apos; The death in captivity without return is the reversal of the promised land theology: YHWH&apos;s gift to Abraham and his descendants was the specific land of Canaan as their perpetual inheritance. To die in a foreign land, unburied in the covenant soil, is the most complete form of covenant displacement in the ancient Near Eastern mind.</p>",
    "13": "<p><strong>hoy boneh beto belo-tzedek vaaliyotav belo mishpat</strong> (<em>hôy bōneh bêtô bĕlōʾ-ṣedeq wăʿăliyyōtāw bĕlōʾ mišpāṭ</em>): &apos;Woe to him who builds his palace through injustice and his upper rooms through unrighteousness.&apos; The <em>hoy</em> (woe) formula opens a formal lament-curse, typically used over the dead (cf. 1 Kgs 13:30: &apos;woe, my brother!&apos;). Applying it to a living king is a death pronouncement while still alive. The two-part accusation — building without <em>tzedek</em> (justice/right) and without <em>mishpat</em> (justice/procedure) — inverts the demand of v. 3. The specific violation: <em>bere&apos;ehu ya&apos;avod chinam upho&apos;alo lo yitten lo</em> (making his countrymen work for nothing, not paying wages) — a direct violation of Lev 19:13 and Deut 24:14-15.</p>",
    "14": "<p><strong>ha&apos;omer evneh-li beit middot vaaliyot mevushot</strong> (<em>hāʾōmēr ʾebneh-lî bêt middôt wăʿăliyyôt mĕruwwāḥôt</em>): &apos;Who says, &apos;I will build myself a grand palace with large upper rooms.&apos;&apos; The specific features listed — cedar paneling (<em>sapun bearazim</em>) and red paint/ochre (<em>shaoh beshasha</em>) — are the luxury markers of elite construction. Red ochre was expensive; cedar from Lebanon was the prestige building material. The contrast with the modest requirements of Josiah&apos;s just reign (vv. 15-16) makes Jehoiakim&apos;s palace an explicit monument to self-indulgence at the expense of covenant responsibility.</p>",
    "15": "<p><strong>hatimaloch ki attah mitcharer baaretz</strong> (<em>hătimloḵ kî ʾattāh mitḥārēr bāʾārez</em>): &apos;Do you think that making yourself a rival in cedar proves you are a king?&apos; The rhetorical question punctures royal pretension: cedar paneling is not the measure of kingship. The contrast is immediate: <em>avicha</em> (your father, Josiah) &apos;ate and drank&apos; — lived normally and adequately — &apos;but also practiced justice and righteousness, and things went well for him.&apos; <em>Asah mishpat utzedaqah</em> (practiced justice and righteousness) repeats v. 3&apos;s demand but now as historical example: Josiah actually did it, and it worked. The causal connection between covenant justice and <em>tov lo</em> (things went well for him) is stated flatly as historical fact.</p>",
    "16": "<p><strong>dan din-ani veevyon az tov halo hi hada&apos;at oti neum YHWH</strong> (<em>dān dîn-ʿānî wĕʾebyôn ʾāz ṭôb hălōʾ-hîʾ haddaʿat ʾōtî nĕʾum Yhwh</em>): &apos;He defended the cause of the poor and needy; then it went well. Is that not what it means to know me? declares the LORD.&apos; This is one of the most important prophetic equations in the entire OT: <em>da&apos;at YHWH</em> (knowing YHWH) is defined as defending the poor and needy, not as theological knowledge. The question is rhetorical — it demands the answer &apos;yes.&apos; To know YHWH in the covenantal sense (<em>yada&apos;</em>) is not intellectual belief about YHWH but relational fidelity expressed in the concrete treatment of the vulnerable. Hosea establishes the same equation (Hos 4:1-2: &apos;no faithfulness, no loyalty, no knowledge of God in the land, but cursing, lying, murder, stealing, adultery&apos;); Matthew&apos;s parable of the sheep and goats (Matt 25:31-46) is the NT&apos;s most direct restatement: &apos;whatever you did for one of the least of these brothers ... you did for me.&apos;</p>",
    "17": "<p><strong>ki eyn eineicha velibcha ki im al-bitscha veal-dam hanaqui</strong> (<em>kî ʾên ʿênêkā wĕlibbĕkā kî ʾim-ʿal-biṣʿekā wĕʿal-dam hannāqî</em>): &apos;But you have no eyes or heart for anything except your own dishonest gain, and for shedding innocent blood.&apos; <em>Betzaʿ</em> (dishonest gain / greed for cut-off profit) is related to the verb &apos;cut off&apos; — profit extracted by cutting off others&apos; rights. The three parallel sins — dishonest gain (<em>vetza</em>), innocent blood (<em>dam hanaqui</em>), oppression (<em>ashaq</em>), and violence (<em>mirtzah</em>) — are the diagnostic opposite of v. 3&apos;s demands. Jehoiakim is the anti-Josiah.</p>",
    "18": "<p><strong>lachen koh-amar YHWH el-Yehoyaqim ben-Yoshiyahu</strong>: &apos;Therefore this is what the LORD says about Jehoiakim son of Josiah.&apos; The death lament for Jehoiakim inverts the standard royal mourning. The double-negative structure — &apos;no one will mourn for him, crying &apos;Ah, my brother!&apos; ... no one will mourn for him, crying &apos;Ah, my lord!&apos;&apos; — lists the two standard forms of kinship lament (sibling lament and subject lament) and denies both. <em>Hoy achi / hoy achot</em> (ah, my brother / ah, my sister) are the laments of equals; <em>hoy adon / hoy hodoh</em> (ah, my lord / alas, his glory) are the laments of subjects. A king who deserves neither is stripped of all relational legitimacy.</p>",
    "19": "<p><strong>kevurat chamor yiqaver sakhov vehashlelech mehal&apos;ah sha&apos;arei Yerushalaim</strong> (<em>qĕbûrat ḥămôr yiqqābēr sāḥôb wĕhašlēk mĕhāʿléh šaʿărê yĕrûšālāyim</em>): &apos;He will be buried like a donkey — dragged away and thrown outside the gates of Jerusalem.&apos; Burial was essential to ancient dignity; proper burial was a mark of covenant community. To be &apos;buried like a donkey&apos; means unburied, discarded as animal waste. The exact fulfillment of this prophecy is unclear — 2 Kgs 24:6 says only that &apos;Jehoiakim slept with his fathers,&apos; which may be formulaic. Josephus and extra-biblical sources suggest he was killed by Nebuchadnezzar&apos;s soldiers. Whether thrown outside Jerusalem&apos;s gates or not, the oracle announces disgrace rather than honor.</p>",
    "20": "<p><strong>ali halvanon utz&apos;aqi uvbashan teni qolech</strong> (<em>ʿălî hallĕbānôn ûṣĕʿāqî ûbabāšān tĕnî qôlēk</em>): &apos;Go up to Lebanon and cry out; lift your voice in Bashan; cry from the passes of Abarim.&apos; Jerusalem is addressed as a woman crying from the highest vantage points — Lebanon (north), Bashan (northeast, the Transjordanian plateau), and Abarim (east, the passes facing Moab from which Moses viewed the land). The three geographic extremes form a complete compass: Jerusalem&apos;s mourning cry reaches to the edges of the surrounding lands. &apos;All your allies have been shattered&apos; (<em>nishbaru kol-me&apos;ahavayich</em>) — the political alliances that Jerusalem trusted instead of YHWH have failed.</p>",
    "21": "<p><strong>dibarti elaich bishalvotayich amarti lo eshma</strong> (<em>dibbartî ʾēlayik bĕšalwōtāyik ʾāmartî lōʾ ʾešmāʿ</em>): &apos;I warned you when you were at ease, but you said, &apos;I will not listen.&apos;&apos; The historical retrospective: YHWH&apos;s warnings came during periods of prosperity (<em>shalvah</em>, ease/rest) — exactly when they would least be heard. The assessment &apos;this has been your habit from your youth&apos; (<em>zeh darkech mine&apos;uraiich</em>) makes the refusal constitutional, not occasional. The &apos;youth&apos; (<em>ne&apos;urim</em>) of the nation refers to the wilderness period — the foundational era of Israelite existence was already characterized by refusal to listen (cf. Deut 9:7: &apos;from the day you left Egypt until you arrived here you have been rebellious&apos;).</p>",
    "22": "<p><strong>kol-ro&apos;ayich tir&apos;eh ruach</strong> (<em>kol-rōʿayik tirʿeh rûaḥ</em>): &apos;The wind will sweep away all your rulers.&apos; <em>Ro&apos;ayich</em> (your shepherds/rulers) — the same shepherd metaphor for political leadership (cf. ch. 23, where YHWH indicts the shepherds). <em>Ruach</em> (wind) — the same empty-wind metaphor as 5:13 (&apos;the prophets are nothing but wind&apos;). The shame and disgrace of v. 22b uses the feminine suffix — Jerusalem personified as a woman whose lovers (political allies) have gone into captivity. Her wickedness (<em>ra&apos;atayich</em>) is the source of her shame.</p>",
    "23": "<p><strong>yoshevet baLevanon menunnah baaruzim</strong> (<em>yōšebet ballĕbānôn mĕqunnenat bāʾărāzîm</em>): &apos;You who live in Lebanon, nestled among the cedars — how you will groan when birth pangs seize you.&apos; The birth-pain metaphor (<em>chil keyoledet</em>) for the pain of judgment recurs throughout Jeremiah (4:31; 6:24; 13:21; 30:6) and the prophets (Isa 13:8; 21:3; Mic 4:9-10). Nestling among the cedars — the symbol of royal luxury (the palace was built of cedar) — does not provide security. The cedar house of Lebanon, the ultimate royal fortress in imagery, will be unable to shelter its inhabitants from divine judgment.</p>",
    "24": "<p><strong>chay-ani neum YHWH ki im-yihyeh Conyahu ben-Yehoyaqim melech Yehudah hotam al yad yemini</strong> (<em>ḥay-ʾănî nĕʾum Yhwh kî ʾim-yihyeh konyāhû ben-yĕhôyāqîm melek yĕhûdāh ḥôtām ʿal yad yĕmînî</em>): &apos;As surely as I live, even if Coniah were the signet ring on my right hand, I would still pull you off.&apos; <em>Hotam</em> (signet ring) — the personal seal of the king, worn on the right hand, used to authenticate royal documents (cf. Esther 3:10; Hag 2:23 where YHWH reverses this judgment for Zerubbabel: &apos;I will make you like a signet ring&apos;). Removing the signet ring is the removal of royal authority and identity. The self-oath (<em>chay-ani</em>, as I live) gives the judgment the same weight as YHWH&apos;s own existence.</p>",
    "25": "<p><strong>unetaticha beyad mevaqashei nafshecha</strong> (<em>ûnĕtattîkā bĕyad mĕbaqqĕšê napšĕkā</em>): &apos;I will hand you over to those who seek your life and whom you dread.&apos; <em>Mevaqashei nafshecha</em> (those who seek your life) is the covenant formula for mortal enemies who seek to kill (cf. 1 Kgs 19:10; Jer 11:21; 38:16). The specific identification — Nebuchadnezzar and the Chaldeans — names the feared enemy by name. The contrast with Hezekiah&apos;s deliverance from Sennacherib (Isa 37) is implicit: where earlier faith brought miraculous rescue, here covenant unfaithfulness brings the very enemy they feared.</p>",
    "26": "<p><strong>vehitriti otcha ve&apos;et immecha asher yeladatcha al-ha&apos;aretz asher lo yoladtem sham</strong>: &apos;I will hurl you and the mother who gave birth to you into another country — a land where neither of you was born.&apos; The hurling (<em>hieriti</em>, violent casting away) of both king and queen mother reflects the significance of the <em>gevirah</em> (queen mother) in Judean royal tradition: the mother&apos;s name is recorded alongside each king&apos;s accession (2 Kgs 24:8). Jehoiachin&apos;s exile in 597 BCE with his mother Nehushta was the historical fulfillment of this oracle (2 Kgs 24:12-15).</p>",
    "27": "<p><strong>ve&apos;el-ha&apos;aretz asher hem menas&apos;im et-nafshsham lashuv sham lo yashuvu</strong>: &apos;As for the land they long to return to — they will never return there.&apos; The word <em>nasa&apos;im nafshsham</em> (they long with all their being / lift up their soul) is the same expression as &apos;lifting up the soul to YHWH&apos; in Ps 25:1; 86:4 — the most intense yearning. The refusal of return makes the exile permanent in its first announcement: no return is promised for Jehoiachin and Nehushta. Historically, Jehoiachin was eventually released from prison by Evil-merodach (2 Kgs 25:27-30) but lived in Babylon until his death, never returning to Judah.</p>",
    "28": "<p><strong>ha-etsev nivzeh nefutz ha-ish hazeh Conyahu</strong> (<em>hăʾeṣeb nibzāh nāpûṣ hāʾîš hazzeh konyāhû</em>): &apos;Is this man Coniah nothing but a broken, despised clay pot — something no one wants?&apos; The three epithets — <em>etsev</em> (clay vessel/idol), <em>nivzah</em> (despised/worthless), <em>naphuts</em> (broken/shattered) — progressively strip the king of dignity. The rhetorical question voices bewilderment at the magnitude of the fall: from the signet ring of YHWH&apos;s right hand (v. 24) to a broken jar no one wants. <em>Keleh she&apos;ein chefrtz bo</em> (an object no one wants) — used for the worthless in Ps 22:6 and Isa 53:3 (of the Suffering Servant: &apos;despised and rejected&apos;).</p>",
    "29": "<p><strong>eretz eretz eretz shim&apos;i dvar YHWH</strong> (<em>ʾereṣ ʾereṣ ʾereṣ šimĕʿî dĕbar Yhwh</em>): &apos;O land, land, land, hear the word of the LORD!&apos; The triple repetition of <em>eretz</em> (land/earth) is unparalleled in its forcefulness — a rhetorical triple that in the OT typically marks divine solemnity or grief (cf. Ezek 21:27: &apos;ruin, ruin, ruin!&apos;; Isa 6:3: &apos;holy, holy, holy&apos;). The land itself is summoned as witness — an extension of the covenant lawsuit (<em>rib</em>) form where heaven and earth are called as witnesses (Deut 32:1; Isa 1:2; Mic 1:2). The land must hear what the human inhabitants refused to hear.</p>",
    "30": "<p><strong>kitivu et-ha&apos;ish hazeh ariri gever lo yitzlach beyamav</strong> (<em>kitĕbû ʾet-hāʾîš hazzeh ʿărîrî geber lōʾ yiṣlaḥ bĕyāmāyw</em>): &apos;Record this man as though childless — a man who will not prosper in his lifetime; for none of his descendants will succeed in sitting on the throne of David and ruling over Judah.&apos; <em>Ariri</em> (childless, literally &apos;stripped bare&apos;) is a legal-status term (cf. Gen 15:2; Lev 20:20-21) meaning without legitimate heirs for succession. The decree is specifically about the throne: none of Coniah&apos;s seed will <em>yoshev al-kise David vemoshel od biYehudah</em> (sit on the throne of David and rule in Judah). This creates the NT&apos;s genealogical problem and its solution: Matthew 1:12 includes Jeconiah (Coniah) in Jesus&apos;s legal genealogy through Joseph, while Luke 3:27 traces through a different Shealtiel and Zerubbabel. The virgin birth dissolves the curse: Jesus is legally Joseph&apos;s heir (establishing Davidic lineage) but not biologically so (bypassing the throne-curse on Jehoiachin&apos;s biological descendants). The &apos;childless&apos; decree applies to throne succession through natural birth; the adoptive-legal lineage of the Son of David born of a virgin escapes it.</p>"
  },
  "23": {
    "1": "<p><strong>hoy ro&apos;im ha-movdim umefitzim et-tzon mar&apos;iti</strong> (<em>hôy rōʿîm hamʾabĕdîm ûmĕpîṣîm ʾet-ṣōʾn marʿîtî</em>): &apos;Woe to the shepherds who destroy and scatter the sheep of my pasture!&apos; The <em>hoy</em> (woe) oracle against the shepherds. <em>Ro&apos;im</em> (shepherds) is the standard prophetic metaphor for political and religious leaders (cf. Ezek 34; Zech 11; John 10:11-16). <em>Mar&apos;iti</em> (my pasture) — the possessive pronoun makes the sheep YHWH&apos;s directly: the shepherds are stewards, not owners. <em>Movdim</em> (destroying) and <em>mefitzim</em> (scattering) are the two failures: the leaders both destroy by active harm and scatter by passive neglect. The &apos;pasture&apos; image connects to Ps 23 and Ezek 34&apos;s divine shepherd counterpart.</p>",
    "2": "<p><strong>atem hafitzothem et-tzoni vatdachu otam velo feqadtem otam</strong> (<em>ʾattem hăpîṣôtem ʾet-ṣōʾnî wattiddĕḥû ʾôtām wĕlōʾ pĕqadtem ʾôtām</em>): &apos;You have scattered my flock and driven them away, and have not cared for them.&apos; The double accusation uses <em>nadach</em> (drive away forcibly) and the negation of <em>paqad</em> (attend to/care for). <em>Paqad</em> is the comprehensive verb for YHWH&apos;s covenantal attention: to visit in blessing (Gen 21:1: &apos;the LORD visited Sarah&apos;), to call to account in judgment (Exod 20:5: &apos;visiting the iniquity&apos;), to appoint to a task (Num 3:10). The leaders have not &apos;paqad&apos;-ed the flock: no attention, no care, no accountability. So YHWH will now <em>paqad</em> the evil of their deeds upon them — the same verb in both accusation and punishment.</p>",
    "3": "<p><strong>va&apos;ani aqbetz et-she&apos;erit tzoni mikkol ha&apos;aratzot asher hidachti otam sham</strong>: &apos;I myself will gather the remnant of my flock from all the lands where I have driven them, bring them back to their pasture, and they will be fruitful and multiply.&apos; The pronoun <em>va&apos;ani</em> (I myself / and I) emphasizes that YHWH directly takes on the task the failed shepherds abandoned. The remnant (<em>she&apos;erit</em>) gathered from all lands is the core of the restoration promise. <em>Paru veravvu</em> (fruitful and multiply) echoes Gen 1:28 and 9:1 — the re-creation formula signals that the gathering of exiles is a new creation act. Jesus&apos;s sending of the twelve (Matt 10:6) and his claim to be the Good Shepherd who gathers the lost sheep of the house of Israel (Matt 15:24; John 10:16) enacts this promise personally.</p>",
    "4": "<p><strong>vahaqimoti aleichem ro&apos;im varou otam</strong> (<em>wahăqimōtî ʿălêkem rōʿîm ûrāʿû ʾôtām</em>): &apos;I will raise up shepherds who will truly care for them; they will no longer be afraid or terrified, and none will be lost.&apos; The promise of proper shepherds (<em>ro&apos;im</em>) is the positive counterpart to the woe-oracle against the bad shepherds. <em>Lo yira&apos;u velo yechatu velo yipaqedu</em> (no longer afraid, terrified, or missing/lost) — three negations that reverse the flock&apos;s current state of fear, panic, and loss. <em>Lo yipaqedu</em> uses the <em>paqad</em> root again: none will be &apos;lacking&apos; in the sense of unaccounted for. This anticipates the parable of the lost sheep (Luke 15:3-7): the good shepherd leaves the ninety-nine to find the one that is missing.</p>",
    "5": "<p><strong>hineh yamim baim neum YHWH vahaqimoti leDavid tzemach tzaddiq</strong> (<em>hinnēh yāmîm bāʾîm nĕʾum Yhwh wăhăqîmōtî lĕdāwid ṣemaḥ ṣaddîq</em>): &apos;The days are coming, declares the LORD, when I will raise up for David a righteous Branch.&apos; <em>Tzemach</em> (branch/shoot/sprout) is the technical messianic title used in Zech 3:8 (&apos;my servant the Branch&apos;), Zech 6:12 (&apos;the man whose name is the Branch&apos;), and Jer 33:15 (repetition of this verse). <em>Tzaddiq</em> (righteous) — the quality the current kings lacked (ch. 22 throughout). The Branch raised up &apos;for David&apos; (<em>leDavid</em>) fulfills the Davidic covenant promise (2 Sam 7:12: &apos;I will raise up your offspring after you&apos;) after the covenant-line kings have all failed. <em>Melek vemaslach uasah mishpat utzedaqah ba-aretz</em> (reign as king, act wisely, establish justice and righteousness in the land) — the accumulated demands of all the failed kings (22:3, 15) are fulfilled by this one figure.</p>",
    "6": "<p><strong>YHWH Tzidqenu</strong> (<em>Yhwh ṣidqênû</em>): &apos;The LORD Our Righteousness.&apos; This is the messianic name — the most Christologically direct name in Jeremiah. The name does two things at once: (1) it identifies the Branch as YHWH himself present in human form (the divine name YHWH is part of the messianic title); (2) it identifies the covenant problem solved: <em>tzidqenu</em> (our righteousness) means the righteousness the covenant required but Israel could never provide is now provided by YHWH himself in the person of his anointed. Paul&apos;s formulation — &apos;God made him who knew no sin to be sin for us, so that in him we might become the righteousness of God&apos; (2 Cor 5:21) and &apos;Christ Jesus, who has become our wisdom, our righteousness, our holiness and our redemption&apos; (1 Cor 1:30) — are the explicit NT appropriation of this messianic name. The name also appears again at Jer 33:16 where, remarkably, it is given to Jerusalem itself — the community named after its king&apos;s character.</p>",
    "7": "<p><strong>lachen hineh yamim baim neum YHWH velo-yomru od chai YHWH asher he&apos;elah et-benei Yisrael me&apos;eretz Mitzraim</strong>: &apos;So the days are coming when no one will say any longer, &apos;As the LORD lives who brought the Israelites up from the land of Egypt.&apos;&apos; The eschatological new-exodus supercedes the old Exodus as the defining saving act. The oath formula &apos;as the LORD lives who brought Israel from Egypt&apos; was the standard covenantal oath (cf. 16:14-15, an almost identical passage). The replacement of the foundational exodus narrative with a greater one is a bold claim: the future redemption will be so vastly greater that the Exodus — the paradigmatic act of salvation — will recede in comparison. Paul&apos;s &apos;once a slave, now a son&apos; language (Gal 4:3-7) and the entire Letter to the Hebrews (Heb 3-4: a greater Moses, a greater rest) develops this Jeremianic logic.</p>",
    "8": "<p><strong>ki im-chai YHWH asher he&apos;elah ve&apos;asher hevi et-zera beit Yisrael me&apos;eretz tzafon</strong>: &apos;But, &apos;As the LORD lives who brought up the descendants of Israel from the north country.&apos;&apos; The north country (<em>eretz tzafon</em>) is Babylon — the new defining place of captivity and liberation. Just as the Exodus defined YHWH as the God who rescues from Egypt, the new exodus will define him as the God who brings back from Babylon and from all the dispersed lands. The universal scope — &apos;and from all the countries where he had driven them&apos; — expands beyond the historical Babylonian exile to include all diasporas.</p>",
    "9": "<p><strong>lanevi&apos;im nishbar libi veqirbi kol-atzmotai raafa</strong> (<em>lannĕbiʾîm nišbar libbî wĕqirbî kol-ʿaṣmôtay rāʿăpû</em>): &apos;My heart is broken within me; all my bones tremble.&apos; This is one of the most raw expressions of prophetic pathos in Scripture. The &apos;broken heart&apos; (<em>lev nishbar</em>) — the same root as the &apos;broken and contrite heart&apos; of Ps 51:17 — here is Jeremiah&apos;s heart breaking over the state of the prophetic community rather than his own sin. &apos;Like a drunken man, like a man overcome by wine&apos; (<em>kish avar yayin vekigever gabar bo yayin</em>): the divine word overwhelms Jeremiah&apos;s capacity to stand firm, leaving him staggering. This uncontrolled response to the holy word is parallel to Daniel&apos;s falling on his face (Dan 8:17), John&apos;s falling as dead (Rev 1:17), and Isaiah&apos;s undone response to the vision (Isa 6:5).</p>",
    "10": "<p><strong>ki-mealeifem nina&apos;afu ha-aretz avlu</strong> (<em>kî-mĕʾalĕpîm niʾăpāh hāʾāreṣ ʾāḇĕlāh</em>): &apos;For the land is full of adulterers. Because of the curse the land mourns.&apos; <em>Ninafu</em> (full of adulterers) — both literal sexual unfaithfulness and the prophetic metaphor for idolatry (cf. Hos 4:2: &apos;there is swearing, lying, murder, stealing, committing adultery; they break all bounds&apos;). The land itself mourns (<em>avlah</em>) in response — creation sympathetically grieving the covenant violation (cf. Rom 8:22: &apos;the whole creation has been groaning&apos;). The phrase &apos;the wilderness pastures are dried up&apos; (<em>yavshu ne&apos;ot midbar</em>) connects moral failure to ecological consequence: the land&apos;s fertility depends on covenant fidelity.</p>",
    "11": "<p><strong>gam navi gam-kohen chanfu</strong> (<em>gam-nābîʾ gam-kōhēn ḥānēpû</em>): &apos;Both prophet and priest are godless; even in my own house I have found their wickedness.&apos; <em>Chaneph</em> (godless/profane/corrupt) carries the sense of defilement through transgression — the breaking of sacred boundaries. The house of YHWH (<em>beiti</em>, the temple itself) has been defiled by prophetic and priestly corruption — the sacred space is no longer protected by its designated guardians. Ezekiel&apos;s temple-vision (Ezek 8) provides the detailed picture of what this corruption looked like.</p>",
    "12": "<p><strong>lachen yihyeh darkam lahem kehalaqlaqqot ba-afelah</strong> (<em>lākēn yihyeh darkām lāhem kaḥălaqlaqqôt bāʾăpēlāh</em>): &apos;Therefore their path will be like slippery ground in the darkness; they will be driven stumbling along it and fall.&apos; <em>Chalaqlaqqot</em> (slippery places) — the same image as Ps 35:6 (&apos;let their path be dark and slippery&apos;) for divine judgment on the wicked. The &apos;year of their reckoning&apos; (<em>shenat peqadatam</em>) uses the <em>paqad</em> root: the year when YHWH will visit them as he promised. The reckoning falls on the year the punishment arrives — not arbitrary but scheduled in the divine economy.</p>",
    "13": "<p><strong>uvnevi&apos;ei Shomeron ra&apos;iti tiflet</strong> (<em>ûbnĕbîʾê šōmĕrôn rāʾîtî tiplet</em>): &apos;In the prophets of Samaria I saw a repulsive thing: they prophesied by Baal and led my people Israel astray.&apos; The comparison structure (Samaria = bad; Jerusalem = worse) is a rhetorical intensification. Baal-prophets in Samaria led Israel into explicit idolatry — the offense is clear. But the Jerusalem prophets&apos; sin is greater because it is more subtle and more spiritually lethal: they use YHWH&apos;s name for their lies.</p>",
    "14": "<p><strong>uvnevi&apos;ei Yerushalaim ra&apos;iti sha&apos;aruriyah na&apos;of vehalokh vashaqer</strong> (<em>ûbnĕbîʾê yĕrûšālaim rāʾîtî šaʿărûrîyāh niʾôp wĕhālôk baššāqer</em>): &apos;But in the prophets of Jerusalem I have seen something even more horrible: they commit adultery and live by lies; they encourage evildoers so that no one turns from his evil.&apos; <em>Sha&apos;aruriyah</em> (horrifying/shocking thing) is stronger than <em>tiflet</em> (repulsive, v. 13) — Jerusalem is worse. The specific sins: adultery (<em>niuf</em>), lies (<em>shaqer</em>), and the pastoral failure of encouraging evildoers (<em>hezeq yedei mere&apos;im</em>) so that no one repents. The last item is the most serious: pastoral corruption that prevents repentance is corruption at the most fundamental level. <em>Hayyu li kulam kesodom veyosheveiha ke&apos;amorah</em> (they have all become to me like Sodom, their inhabitants like Gomorrah) — the ultimate prophetic judgment, since Sodom and Gomorrah were destroyed without remnant.</p>",
    "15": "<p><strong>lachen koh-amar YHWH Tzvaot al-hanevi&apos;im hineni maachilem laanah</strong>: &apos;Therefore thus says the LORD of hosts concerning the prophets: I am going to feed them wormwood and give them poisoned water to drink.&apos; <em>La&apos;anah</em> (wormwood, a bitter desert plant) and <em>mei rosh</em> (water of poison/gall) are images of bitter judgment (cf. Lam 3:15, 19; Amos 5:7; Rev 8:11). The poisoned feeding is measure-for-measure: they fed the people with false spiritual food (&apos;false hopes&apos;, v. 16); YHWH feeds them with bitterness. The spread of ungodliness (<em>chanuppah</em>) from Jerusalem&apos;s prophets throughout the land is the ecological disaster of false prophecy.</p>",
    "16": "<p><strong>al-tishme&apos;u el-divrei hanevi&apos;im hanivi&apos;im lachem mahbilim atem et-hazon libam yedaberu</strong>: &apos;Do not listen to the prophets who are prophesying to you. They are filling you with false hopes; they speak visions from their own imagination, not from the mouth of the LORD.&apos; <em>Mahbilim</em> (filling with false hopes / making vain) from <em>hevel</em> (vanity/breath/nothing — Ecclesiastes&apos; signature word). <em>Chazon libam</em> (visions of their own heart/mind) is the diagnosis: they prophesy from their own imagination, not from divine revelation. The criterion for authenticity is &apos;from the mouth of the LORD&apos; (<em>mipi YHWH</em>) — the standard that Deut 18:18-19 established for the true prophet-like-Moses.</p>",
    "17": "<p><strong>omrim lemaneatzei dvar YHWH shalom yihyeh lachem</strong> (<em>ʾōmĕrîm lĕmĕnaʾăṣê dĕbar Yhwh šālôm yihyeh lākem</em>): &apos;They keep telling those who follow the stubbornness of their own heart, &apos;No disaster will come upon you.&apos;&apos; The false prophets are pastoral parasites: they tell those who despise the word of YHWH that all will be well. <em>Menatze dvar YHWH</em> (despises the word of YHWH) — the very people whose conduct requires confrontation are promised comfort. The &apos;stubbornness of their own heart&apos; (<em>sherirut libam</em>) is the diagnostic phrase recurring throughout Jeremiah (3:17; 7:24; 9:14; 11:8; 13:10; 16:12; 18:12) for the willful self-determination that rejects YHWH&apos;s direction.</p>",
    "18": "<p><strong>ki mi amad besod YHWH vayar vayishma et-dvaro</strong> (<em>kî mî ʿāmad bĕsôd Yhwh wĕyirʾ wĕyišmaʿ ʾet-dĕbārô</em>): &apos;For which of them has stood in the LORD&apos;s council to see and hear his word?&apos; <em>Sod YHWH</em> (the council/assembly/secret of YHWH) is the divine court — the heavenly assembly of YHWH surrounded by celestial beings, from which prophetic commissions are issued (cf. 1 Kgs 22:19-23 where Micaiah sees the divine court; Isa 6 where Isaiah is commissioned from the heavenly throne-room; Job 1-2 where the divine court is depicted). Standing in YHWH&apos;s council is the criterion that separates true prophets from false: genuine prophets receive their message from a direct divine commission within the heavenly court, while false prophets generate messages from their own hearts. Amos 3:7 states the same principle: &apos;Surely the LORD God does nothing without revealing his secret (<em>sod</em>) to his servants the prophets.&apos;</p>",
    "19": "<p><strong>hineh se&apos;arat YHWH chemah yatza&apos;ah usa&apos;ar mitgolelel</strong> (<em>hinnēh saʿărat Yhwh ḥēmāh yāṣĕʾāh wĕsaʿar miṯgôlēl</em>): &apos;Behold, the storm of the LORD! His wrath has gone out, a swirling tempest; it will fall violently on the head of the wicked.&apos; The divine storm-wind (<em>se&apos;arah</em>) is the theophanic vehicle used in Ezekiel&apos;s inaugural vision (Ezek 1:4), Job&apos;s divine speech (Job 38:1), and Elijah&apos;s translation (2 Kgs 2:1, 11). Here it is specifically judicial — the storm of divine wrath (&apos;on the head of the wicked&apos;) that the false prophets are failing to announce.</p>",
    "20": "<p><strong>lo yashuv af-YHWH ad-asoto ve&apos;ad-haqimo mezimot libo</strong> (<em>lōʾ yāšûb ʾap-Yhwh ʿad-ʿăśōtô wĕʿad-hăqîmô mĕzimmôt libbô</em>): &apos;The LORD&apos;s anger will not turn back until he has accomplished the purposes of his heart. In the latter days you will understand it clearly.&apos; The phrase <em>be&apos;acharit hayamim</em> (in the latter days / end of days) has both near-future (the exile) and eschatological senses. The understanding that will come &apos;in the latter days&apos; is retrospective comprehension: what seems obscure now will be transparent after the judgment falls. Repeated at 30:24 as the bookend of the &apos;Book of Consolation.&apos;</p>",
    "21": "<p><strong>lo-shalach&apos;ti et-haneviim vehem ratzu lo dibbarti aleyhem vehem niv&apos;au</strong> (<em>lōʾ-šālaḥtî ʾet-hannĕbiʾîm wĕhēm rāṣû lōʾ-dibbartî ʾălêhem wĕhēm nibbāʾû</em>): &apos;I did not send these prophets, yet they went running; I did not speak to them, yet they prophesied.&apos; The double denial — &apos;I did not send ... I did not speak&apos; — strips the false prophets of both authorization and content. The running without being sent (<em>vayaratz</em>) echoes Deut 18:20: &apos;the prophet who presumes to speak a word in my name that I have not commanded him to speak ... shall die.&apos; The running enthusiasm of the false prophets is not a mark of authentic prophetic compulsion (cf. Amos 3:8: &apos;the lion has roared — who will not fear? The LORD God has spoken — who can but prophesy?&apos;) but of unauthorized self-promotion.</p>",
    "22": "<p><strong>ve&apos;im-amdu besodi veyashme&apos;u et-devaray et-ami veshibum midarkam hara&apos;ah</strong>: &apos;But if they had stood in my council and proclaimed my words to my people, they would have turned them from their evil ways and evil deeds.&apos; The counterfactual reveals what authentic prophecy would have accomplished: actual repentance (<em>shiv-um midarkam hara&apos;ah</em>, turning them from evil ways). False prophecy fails in its most fundamental purpose — it produces no change of direction. The measure of prophetic authenticity is not dramatic experience but productive effect: genuine divine words bring repentance; manufactured words cannot.</p>",
    "23": "<p><strong>ha-elohei miqarov ani neum YHWH velo elohei merachok</strong> (<em>hăʾĕlōhê miqqārōb ʾănî nĕʾum Yhwh wĕlōʾ ʾĕlōhê mērāḥōq</em>): &apos;Am I only a God nearby, declares the LORD, and not a God far away?&apos; The rhetorical question asserts divine omnipresence by denying its limitation. A &apos;God nearby&apos; would be a local deity — a genius loci who presides over a specific location and could be evaded by leaving that space. The contrast is between a territorial deity (which the pagan gods were) and YHWH, who cannot be geographically escaped. The false prophets think they can tell their private &apos;dreams&apos; without YHWH hearing — v. 23-24 dismantles that assumption.</p>",
    "24": "<p><strong>im-yissater ish bamistorim va&apos;ani lo er&apos;enu neum YHWH halo et-hashamayim ve&apos;et-ha&apos;aretz ani male</strong>: &apos;Can anyone hide in secret places where I cannot see him? ... Do I not fill heaven and earth?&apos; <em>Halo et-hashamayim ve&apos;et-ha&apos;aretz ani male</em> (do I not fill heaven and earth?): divine <em>omnipresence</em> stated as comprehensive spatial occupation. This is the OT&apos;s most direct statement of divine immensity — not merely that YHWH is present everywhere but that his presence fills the cosmos (cf. Ps 139:7-12; Isa 66:1; Acts 17:27-28: &apos;he is not far from each one of us ... in him we live and move and have our being&apos;). The implication for false prophecy: YHWH hears every lie told in his name.</p>",
    "25": "<p><strong>shama&apos;ti et asher amru haneviim hanivi&apos;im bishmi sheqer lemor chalamti chalamti</strong>: &apos;I have heard what the prophets are saying who prophesy lies in my name: &apos;I have dreamed, I have dreamed!&apos;&apos; Dreams as a vehicle of prophetic revelation had legitimate precedent (Gen 37; 1 Sam 28:6; Joel 2:28). The problem is not dreams per se but the use of dream-claims to manufacture authority for messages not received from YHWH. The doubling (<em>chalamti chalamti</em>, I have dreamed, I have dreamed) mimics the false enthusiasm of the prophets — the intensity of the claim inversely proportional to its authenticity.</p>",
    "26": "<p><strong>ad-matai hayesh belev haneviim nivi&apos;ei hashaqer unevei tarmiyt libam</strong>: &apos;How long shall there be lies in the heart of these prophets? They prophesy the deceit of their own hearts.&apos; The <em>ad-matai</em> (how long?) is the lament formula used of prophetic endurance (4:21; Ps 6:3; 13:1-2). The diagnostic: lies originate in the <em>lev</em> (heart) — the false prophet&apos;s problem is not technique but orientation. A heart not aligned with YHWH generates messages aligned with its own desires.</p>",
    "27": "<p><strong>hahoshvim lehashkiach et-ami shemi bechalomotam</strong>: &apos;They intend to make my people forget my name through the dreams they tell one another, just as their fathers forgot my name for Baal.&apos; The naming here is precise: the goal of false prophecy (whether consciously intended or not) is to displace YHWH&apos;s name with something else. In the fathers&apos; generation the displacement was explicit (Baal worship); in Jeremiah&apos;s generation it is happening through false prophecy — replacing the <em>davar YHWH</em> (actual word of YHWH) with manufactured dreams that serve human agendas.</p>",
    "28": "<p><strong>hanavi asher itto chalom yesaper chalom va&apos;asher dvari itto yedaber dvari emet</strong>: &apos;Let the prophet who has a dream tell the dream — but let the one who has my word speak my word faithfully. What does straw have to do with wheat?&apos; The straw/wheat contrast is a refinery metaphor: threshing separates the worthless husk from the valuable grain. The dream may be real, but it is straw relative to the word of YHWH. Both may exist, but they are not equivalent. <em>Emet</em> (faithfully/truthfully) — the standard of transmission: even if the message is genuine, it must be transmitted without distortion.</p>",
    "29": "<p><strong>halo koh dvari ka-esh neum YHWH vekhapatish yefatetz sela</strong> (<em>hălōʾ kōh dĕbārî kāʾēš nĕʾum Yhwh wĕkĕpaṭṭîš yĕpōṣēṣ sālaʿ</em>): &apos;Is not my word like fire, declares the LORD, and like a hammer that shatters rock?&apos; Two images of irresistible destructive power: <em>esh</em> (fire, which consumes without leaving anything) and <em>paratish</em> (a heavy hammer that shatters rock). Both are applied to the divine word — making it causally effective, not merely informational. The hammer/rock image anticipates Matt 7:24-25 where the wise man builds on rock: the word that shatters rock for the unrepentant is the same word that provides foundation for the responsive. Heb 4:12 (&apos;the word of God is living and active ... sharper than any two-edged sword&apos;) develops the same image of the word&apos;s penetrating power.</p>",
    "30": "<p><strong>lachen hineni al-haneviim neum YHWH megannevi divrai ish mere&apos;ehu</strong>: &apos;Therefore, I am against the prophets, declares the LORD, who steal my words from each other.&apos; The triple <em>hineni al</em> (I am against, vv. 30-32) is a formal declaration of divine opposition used in judgment oracles against nations (cf. Ezek 26:3; 28:22; 29:3). &apos;Stealing words from each other&apos; — the false prophets plagiarize each other&apos;s messages, recycling visions and dreams as their own without any actual divine encounter. The professionalization of prophecy has become an echo chamber of borrowed falsehoods.</p>",
    "31": "<p><strong>hineni al-haneviim neum YHWH halosheim leshonam vayinneum ne&apos;um</strong>: &apos;I am against the prophets, declares the LORD, who wag their own tongues and say, &apos;This is what the LORD declares.&apos;&apos; <em>Leqach leshono</em> (to take his tongue) — the false prophets use the messenger formula (<em>ne&apos;um YHWH</em>) as a mechanical stamp, applying it to messages that originated in their own tongues, not YHWH&apos;s commission. The abuse of the prophetic formula simultaneously claims divine authority and denies it by attaching it to human invention.</p>",
    "32": "<p><strong>hineni al-nivei chalomot shaqer neum YHWH vayesaprum vayat&apos;u et-ami</strong>: &apos;I am against those who prophesy lying dreams ... who lead my people astray with their lies and their recklessness, when I neither sent them nor commissioned them. They are of no benefit whatsoever.&apos; <em>Pachazutam</em> (recklessness/wantonness) — the same root as Judges 9:4&apos;s &apos;reckless and irresponsible&apos; men. The climax: &apos;of no benefit whatsoever&apos; (<em>lo-ho&apos;el yo&apos;ilu</em>) — the double root for usefulness denied twice, the strongest possible negation. False prophecy does not merely fail to help; it actively harms by leading astray.</p>",
    "33": "<p><strong>veki yisha&apos;alcha ha&apos;am hazeh o hanavi o hakohen lemor ma massa YHWH</strong> (<em>wĕkî yišʾālĕkā hāʿam hazzeh ʾô hannābîʾ ʾô hakkōhēn lēmōr mah-massāʾ Yhwh</em>): &apos;When this people, or a prophet or a priest, asks you, &apos;What is the burden of the LORD?&apos; you shall say to them, &apos;You are the burden, and I will cast you off.&apos;&apos; The Hebrew wordplay: <em>massa</em> (burden/oracle) is the standard term for a prophetic pronouncement against the nations (cf. Isa 13:1: &apos;the oracle [<em>massa</em>] concerning Babylon&apos;; Nah 1:1; Hab 1:1; Mal 1:1). But <em>massa</em> also literally means &apos;a burden to be carried.&apos; Jeremiah exploits the double meaning: they ask for the prophetic oracle (<em>massa</em>), but YHWH says they themselves are the burden (<em>massa</em>) he is about to cast off (<em>natashti</em>). The oracle-seekers have become the oracle.</p>",
    "34": "<p><strong>vehanavi vehakohen ve&apos;ish asher yomar massa YHWH</strong>: &apos;As for the prophet, the priest, or any person who says &apos;The burden of the LORD,&apos; I will punish that person and his household.&apos; The punishment extends to the household — the familial unit that benefited from the prophet&apos;s profession. This was standard in ancient legal thinking: corporate household accountability (cf. Achan&apos;s family in Josh 7:24-25). The commercialization of prophecy corrupted the entire household economy built on it.</p>",
    "35": "<p><strong>koh tomeru ish el-re&apos;ehu ve&apos;ish el-achiv meh anah YHWH umah diber YHWH</strong>: &apos;This is what you are to say to one another: &apos;What has the LORD answered?&apos; or &apos;What has the LORD spoken?&apos;&apos; The replacement formula: instead of asking for the &apos;burden&apos; (<em>massa</em>), the community is instructed to ask in straightforward factual terms: what did YHWH answer? what did YHWH say? These questions require specific content, not the oracular formula. The shift from <em>massa YHWH</em> to <em>mah diber YHWH</em> is the shift from prophetic brand to prophetic content.</p>",
    "36": "<p><strong>ki et-massa YHWH tizkeru od ki yihyeh massa ish dvaro</strong>: &apos;You must no longer speak of &apos;the burden of the LORD,&apos; for the burden is every person&apos;s own word, and you have perverted the words of the living God.&apos; The logic: calling human words &apos;the burden of YHWH&apos; is perverting (<em>hafach</em>, overturning/distorting) the words of the living God. <em>Elohim chayim YHWH Tzvaot elohenu</em> (the living God, the LORD of Armies, our God) — the full divine name stacked to emphasize the gravity of the perversion. Using YHWH&apos;s name for human speech is an ontological confusion, not merely a technical violation.</p>",
    "37": "<p>The instruction to the prophet at v. 37 repeats the formula of v. 35 but now addresses the prophet directly rather than the general community. The shift in address — from &apos;you to one another&apos; to &apos;you to the prophet&apos; — shows Jeremiah is providing laypeople with language to hold their prophetic authorities accountable. The same question — what has YHWH answered, what has YHWH spoken — applies to the prophets themselves.</p>",
    "38": "<p><strong>ve&apos;im massa YHWH tomeru lachen koh-amar YHWH ya&apos;an emarchem et-haddavar hazeh massa YHWH</strong>: &apos;But if you say &apos;the burden of the LORD,&apos; thus says the LORD: Because you have spoken these words — &apos;the burden of the LORD&apos; — when I sent word to you that you were not to say &apos;the burden of the LORD.&apos;&apos; The specific disobedience is named: continuing to use the forbidden formula after being explicitly instructed not to. This transforms the formula itself into a test of obedience — using it after the prohibition is itself the violation.</p>",
    "39": "<p><strong>lachen hineni venashiti etchem nasa</strong> (<em>lākēn hinnĕnî wĕnāśîtî ʾetkem nāśōʾ</em>): &apos;Therefore, behold, I will surely lift you up and fling you away from my presence.&apos; The pun completes itself: they asked for the &apos;burden&apos; (<em>massa</em>); YHWH will make them the &apos;lifted up and carried&apos; (<em>nasa</em>) object — carried away and hurled from his presence. The covenant consequence of perverting divine speech is removal from the covenant space: exile from the city YHWH gave them and their fathers.</p>",
    "40": "<p><strong>venatateti aleichem cherpat olam uvoshet olam asher lo tishkach</strong> (<em>wĕnātattî ʿălêkem ḥerpat ʿôlām ûbôšet ʿôlām ʾăšer lōʾ tiššākēaḥ</em>): &apos;And I will bring on you everlasting disgrace and lasting shame that will not be forgotten.&apos; <em>Cherpat olam</em> (everlasting disgrace) and <em>boshet olam</em> (lasting shame) — the two shame-words paired with the qualifier <em>olam</em> (everlasting/perpetual) make the judgment permanent. Not merely temporal punishment but permanent memorial of the false prophets&apos; corruption. The final phrase <em>asher lo tishkach</em> (that will not be forgotten) is the ultimate covenant-judgment: the positive &apos;I will remember their sin no more&apos; of 31:34 is here inverted into permanent remembrance of shame.</p>"
  },
  "24": {
    "1": "<p><strong>hera&apos;ani YHWH vehineh shnei dudaei te&apos;enim mutzagim lifnei heikhal YHWH</strong> (<em>herāʾanî Yhwh wĕhinnēh šĕnê dûdāʾê tĕʾênîm mûṣāgîm lipnê hêkal Yhwh</em>): &apos;The LORD showed me: there before me were two baskets of figs placed before the temple of the LORD.&apos; The vision is temporally located after the 597 BCE deportation of Jeconiah/Jehoiachin. <em>Dudaei te&apos;enim</em> (baskets of figs) — the temple setting suggests an offering context: figs were among the first-fruits brought to the temple (Deut 26:2-10). The historical background: the &apos;best people&apos; (craftsmen, officials) were taken in 597, while the weaker Zedekiah and those left behind congratulated themselves on being the surviving remnant.</p>",
    "2": "<p><strong>hadud echad te&apos;enim tovot meod kibikure hateenah harishonot vedud echad te&apos;enim ra&apos;ot meod</strong>: &apos;One basket had very good figs, like first-ripe figs, but the other basket had very bad figs, so rotten they could not be eaten.&apos; <em>Bikhure</em> (first-ripe, first-fruits) — the early figs of spring (June) were considered the finest, the most prized (cf. Isa 28:4; Mic 7:1). The comparison &apos;like first-ripe figs&apos; sets the standard for excellence. The bad figs are not merely of lower quality but <em>ra&apos;ot meod asher lo-ye&apos;akelna</em> (very bad, which cannot be eaten) — completely inedible, spoiled beyond any use.</p>",
    "3": "<p>The divine dialogue — &apos;What do you see, Jeremiah?&apos; / &apos;Figs&apos; — follows the pattern of the call-visions (1:11-13) where YHWH asks Jeremiah to name what he sees before explaining it. The naming creates engagement: Jeremiah participates in the interpretation process by first observing and describing what is visually obvious (good figs and bad figs) before YHWH supplies the counter-intuitive theological meaning.</p>",
    "4": "<p>The formula <em>vayehi dvar YHWH elai lemor</em> (and the word of the LORD came to me, saying) bridges the vision and its interpretation — standard prophetic formula separating the visionary content from the interpretive oracle. The coming word will invert the expected identification: those in exile (who appear to have been punished) are the good figs; those remaining in Judah (who appear to have been spared) are the bad figs.</p>",
    "5": "<p><strong>keha-te&apos;enim hatovot ha-elleh ken akir et-galut Yehudah asher shilachti min-hamakom hazeh artza kasdim letovah</strong>: &apos;Like these good figs, I will look favorably on the exiles of Judah whom I sent away from this place to the land of the Chaldeans — for their good.&apos; The counter-intuitive reversal: exile (&apos;sent away&apos;) is reinterpreted as divine sending for good. YHWH says &apos;I sent them&apos; (<em>shilachti</em>) — the exile is not Babylon&apos;s victory but YHWH&apos;s surgery, removing the best to preserve them for future restoration. <em>Letovah</em> (for their good) — the same phrase YHWH uses to Joseph about his brothers&apos; intentions (Gen 50:20: &apos;you intended to harm me, but God intended it for good&apos;). The exiles are not being punished; they are being preserved.</p>",
    "6": "<p><strong>veshami et-eini aleihem letovah vashevotim el-ha-aretz hazot uvnitim velo-eherros venata&apos;tim velo-etosh</strong>: &apos;I will keep my eyes on them for good, and I will bring them back to this land. I will build them and not tear them down; I will plant them and not uproot them.&apos; The build/uproot language echoes Jeremiah&apos;s own call in 1:10: he was appointed &apos;to pluck up and to break down ... to build and to plant.&apos; Here YHWH uses the same vocabulary but with the negative forms of the destructive verbs: for the exiles, the tearing-down and uprooting phase is complete; only building and planting remain. The four-part structure (build/not-tear-down, plant/not-uproot) mirrors 1:10&apos;s six verbs reduced to the positive pair.</p>",
    "7": "<p><strong>venatati lahem lev lada&apos;at oti ki-ani YHWH</strong> (<em>wĕnātattî lāhem lēb lādaʿat ʾōtî kî-ʾănî Yhwh</em>): &apos;I will give them a heart to know me, that I am the LORD.&apos; <em>Lev lada&apos;at</em> (a heart to know) is the proto-new-covenant promise: YHWH giving the cognitive and relational faculty of knowing him as a divine gift, not a human achievement. This is the miniature of 31:33-34 (&apos;I will put my Torah in their inner parts and write it on their hearts ... they will all know me from the least to the greatest&apos;) and Ezek 36:26 (&apos;I will give you a new heart&apos;). The formula <em>vayehi li le&apos;am va&apos;ani ehyeh lahem le&apos;elohim</em> (they will be my people and I will be their God) is the covenant formula in its most compressed form (cf. 7:23; 11:4; 30:22; 31:33; 32:38; Lev 26:12; Ezek 36:28; 2 Cor 6:16; Rev 21:3). Returning to YHWH with all their heart (<em>bekhol libam</em>) is the response to the given heart — the gift enables the return.</p>",
    "8": "<p><strong>ukeha-te&apos;enim hara&apos;ot asher lo-ye&apos;akelna miroa&apos; ken ettein et-tzidqiyahu melech Yehudah</strong>: &apos;But as for the bad figs that are so rotten they cannot be eaten — thus says the LORD — so I will treat Zedekiah king of Judah, his officials, the remnant of Jerusalem who remain in this land, and those who live in the land of Egypt.&apos; The bad-fig identification includes Zedekiah&apos;s court (the political establishment left in Judah after 597), the remaining Jerusalemites, and those in Egypt — the community that fled to Egypt against YHWH&apos;s explicit instruction (chs. 42-44). The Egyptians-refugees are already anticipated: they chose Egypt over YHWH&apos;s direction and are placed with the inedible figs.</p>",
    "9": "<p><strong>venatatim lezava&apos;ah lera&apos;ah lechol mamlechot ha&apos;aretz</strong> (<em>ûnĕtattîm lĕzawʿāʾ lĕrāʿāh lĕkol mamlĕkôt hāʾāreṣ</em>): &apos;I will make them a horror to all the kingdoms of the earth — a reproach, a byword, a taunt, and a curse in every place where I drive them.&apos; Four terms of social degradation: <em>zaavah</em> (horror/trembling — causing others to shudder), <em>cherpah</em> (reproach/disgrace), <em>mashal</em> (byword, to be cited as a proverb of shame), and <em>qelalah</em> (curse — the opposite of <em>berakhah</em>). These four echo the comprehensive covenant curses of Deut 28:25, 37 where the same accumulation marks total covenant reversal.</p>",
    "10": "<p><strong>veshilachti bam et-hacherev et-hara&apos;av ve&apos;et-hadever</strong> (<em>wĕšillaḥtî bām ʾet-haḥereb ʾet-hārāʿāb wĕʾet-haddāber</em>): &apos;And I will send the sword, famine, and pestilence against them until they are completely destroyed from the land I gave to them and to their fathers.&apos; The triad of sword (<em>cherev</em>), famine (<em>ra&apos;av</em>), and pestilence (<em>dever</em>) is Jeremiah&apos;s signature covenant-judgment formula — appearing at least twelve times in the book (14:12; 21:7, 9; 27:8, 13; 28:8; 29:17-18; 32:24, 36; 34:17; 38:2; 44:13). These are the three classic covenant curses of Lev 26 and Deut 28 condensed into a triad, representing military defeat, agricultural failure, and plague. Their application to those remaining in the land makes the exile-survival the superior outcome: being taken captive to Babylon is better than facing the triad in Judah.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'jeremiah')
    merge_comm(existing, JER_ORIGINAL)
    save_comm('mkt-original', 'jeremiah', existing)

    out = json.loads((ROOT / 'data/commentary/mkt-original/jeremiah.json').read_text())
    il  = json.loads((ROOT / 'data/interlinear/jeremiah.json').read_text())

    all_ok = True
    for ch in range(22, 25):
        ck = str(ch)
        missing = set(il.get(ck, {}).keys()) - set(out.get(ck, {}).keys())
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(out.get(ck,{}))} verses)')
    if all_ok:
        print('All verses present')

if __name__ == '__main__':
    main()
